import java.io.*;
import java.util.*;

public class Main {
    private static boolean ok(int[] a, int y) {
        int first = a[0] | y;
        for (int i = 1; i < a.length; i++) {
            if ((a[i] | y) != first) return true; // at least two distinct values
        }
        return false;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped newlines ("\\n") with spaces to treat them as separators
        String data = raw.toString().replace("\\\\n", " ");
        StringTokenizer st = new StringTokenizer(data);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            int X = Integer.parseInt(st.nextToken());
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = Integer.parseInt(st.nextToken());
            int ans = 0;
            // Since X <= 2^30-1, iterate bits from 30 down to 0
            for (int b = 30; b >= 0; b--) {
                int cand = ans | (1 << b);
                if (cand <= X && ok(a, cand)) {
                    ans = cand;
                }
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

